{
    "level": "A1–A2",
    "intro": "For the future with <strong>to be</strong>, we use <strong>will be</strong>. The form is the same with every subject.",
    "rules": [
        {
            "label": "will be",
            "color": "emerald",
            "text": "With <strong>I / you / he / she / it / we / they</strong>, the pattern stays the same: <strong>will be</strong>.",
            "example": "I will be at home. / They will be ready."
        },
        {
            "label": "won't be",
            "color": "blue",
            "text": "The negative is <strong>will not be</strong> or <strong>won't be</strong>.",
            "example": "She won't be late."
        },
        {
            "label": "Will ... be?",
            "color": "amber",
            "text": "In questions, move <strong>will</strong> to the front and keep <strong>be</strong> after the subject.",
            "example": "Will he be here? / Will they be ready?"
        }
    ]
}

{
    "title": "1. The form will be",
    "intro": "This is one of the easiest future patterns: every subject takes the same form.",
    "items": [
        {
            "label": "All subjects",
            "title": "will be",
            "subtitle": "I will be there. / She will be tired. / They will be ready."
        },
        {
            "label": "Short forms",
            "title": "'ll be",
            "subtitle": "I'll be late. / She'll be here soon."
        },
        {
            "label": "Negative",
            "title": "will not be / won't be",
            "subtitle": "We won't be at home."
        },
        {
            "label": "Pattern",
            "title": "Subject + will be",
            "subtitle": "He will be busy. / We will be in Paris."
        }
    ]
}

{
    "title": "2. Negatives",
    "intro": "The negative is very simple: <strong>will not be</strong> or <strong>won't be</strong>.",
    "rows": [
        {
            "en": "I will be at home.",
            "ua": "I won't be at home.",
            "note": "won't = will not"
        },
        {
            "en": "She will be tired.",
            "ua": "She will not be tired.",
            "note": "The full form sounds clearer or stronger."
        },
        {
            "en": "They will be late.",
            "ua": "They won't be late.",
            "note": "The form is the same for every subject."
        }
    ],
    "warning": "📌 After <strong>will</strong>, use <strong>be</strong>, not <strong>am / is / are</strong>."
}

{
    "title": "3. Questions",
    "sections": [
        {
            "label": "Will + subject + be",
            "color": "emerald",
            "description": "In a yes/no question, start with <strong>will</strong>, then add the subject and <strong>be</strong>.",
            "examples": [
                {
                    "en": "Will he be here tomorrow?",
                    "ua": "Will he be here tomorrow?"
                },
                {
                    "en": "Will they be ready by noon?",
                    "ua": "Will they be ready by noon?"
                }
            ]
        },
        {
            "label": "Wh-questions",
            "color": "blue",
            "description": "After <strong>where / when / why / who</strong>, we still use <strong>will + subject + be</strong>.",
            "examples": [
                {
                    "en": "Where will you be tonight?",
                    "ua": "Where will you be tonight?"
                },
                {
                    "en": "Why will she be late?",
                    "ua": "Why will she be late?"
                }
            ]
        },
        {
            "label": "Keep be in the pattern",
            "color": "amber",
            "description": "Do not forget <strong>be</strong>: it makes the future form of <strong>to be</strong> complete.",
            "examples": [
                {
                    "en": "She will be at home. → Will she be at home?",
                    "ua": "In the question, <strong>be</strong> stays after the subject."
                },
                {
                    "en": "Will they be busy later?",
                    "ua": "The pattern is the same with every subject."
                }
            ]
        }
    ]
}

{
    "title": "4. Short answers",
    "intro": "In a short answer, we repeat <strong>will</strong> or <strong>won't</strong>, not <strong>be</strong>.",
    "rows": [
        {
            "en": "Will you be at home tonight?",
            "ua": "Yes, I will. / No, I won't.",
            "note": "After Will you...?, we answer with I will / I won't."
        },
        {
            "en": "Will she be ready soon?",
            "ua": "Yes, she will. / No, she won't.",
            "note": "will → she will / she won't"
        },
        {
            "en": "Will they be there tomorrow?",
            "ua": "Yes, they will. / No, they won't.",
            "note": "will → they will / they won't"
        }
    ],
    "warning": "📌 In short answers, repeat <strong>will / won't</strong>, not <strong>be</strong>."
}

{
    "title": "5. Common mistakes",
    "items": [
        {
            "label": "Mistake 1",
            "color": "rose",
            "title": "Using am / is / are after will.",
            "wrong": "❌ He will is late.",
            "right": "✅ <span class=\"font-mono\">He will be late.</span>"
        },
        {
            "label": "Mistake 2",
            "color": "amber",
            "title": "Leaving out be in a question.",
            "wrong": "❌ Will they ready?",
            "right": "✅ <span class=\"font-mono\">Will they be ready?</span>"
        },
        {
            "label": "Mistake 3",
            "color": "sky",
            "title": "Mixing the future of to be with a present form.",
            "wrong": "❌ We are late tomorrow.",
            "right": "✅ <span class=\"font-mono\">We will be late tomorrow.</span>"
        }
    ]
}

